// Clarificação
const clarificar = (
    clarificacao?.precisa_clarificar === true ||
    metadados?.busca_ambigua === true
) ? 1 : 0;

vars['clarificar'] = clarificar;
vars['clarificacaoTipo'] = clarificacao?.tipo || '';
vars['clarificacaoPergunta'] = clarificacao?.pergunta || '';
