// Mensagem de clarificação
const opcoesClarificacao = vars['clarificacaoOpcoes'];
const perguntaBase = vars['clarificacaoPergunta'] || 'Para te indicar a opção certa, preciso de um detalhe:';

let clarificarMensagem = '';
if (clarificar === 1) {
    const listaOpcoes = opcoesClarificacao.length > 0
        ? opcoesClarificacao.map((op, i) => `${i + 1}) ${op}`).join('\n')
        : '';

    clarificarMensagem =
        `${perguntaBase}\n` +
        (listaOpcoes ? `${listaOpcoes}\n` : '') +
        `\nMe diga o número ou escreva a opção desejada.`;
}
vars['clarificarMensagem'] = clarificarMensagem;

// Helpers
function normalizarTipoClassificacao(tipo) {
    return String(tipo || '').toUpperCase().trim();
}

function prefixoTipoClassificacao(tipo) {
    switch (normalizarTipoClassificacao(tipo)) {
        case 'GENERICOS':
            return 'Opção Genérica (Mais econômica 💰)';
        case 'SIMILARES':
            return 'Opção Similar 👍';
        case 'REFERENCIA':
            return 'Opção de Referência ⭐';
        default:
            return 'Opção Disponível';
    }
}

function montarDescricaoLinhaUnica(item) {
    let descCompleta = item.desc;

    const prefixo = prefixoTipoClassificacao(item.tipoClassificacao);
    descCompleta = `${prefixo} - ${descCompleta}`;

    if (item.badge) {
        descCompleta = `${item.badge} - ${descCompleta}`;
    }

    descCompleta += ` | ${item.price}`;

    if (item.infoOferta) {
        descCompleta += item.infoOferta;
    }

    return descCompleta;
}

function processarProduto(produto) {
    if (!produto || !produto.nome) return null;

    const estoqueDisponivel = Number(produto.estoque) || 0;
    if (estoqueDisponivel <= 0) return null;

    const nomeCompleto = produto.nome;
    const codigo = produto.codigo_barras || produto.codigo || '-';

    const precoFinal = Number(produto.precos?.preco_final) || 0;
    const precoCheio = Number(produto.precos?.preco_sem_desconto) || null;
    const desconto = Number(produto.precos?.desconto_percentual) || 0;

    let preco = '';
    let temOferta = false;

    if (precoFinal > 0) {
        if (precoCheio && precoFinal < precoCheio) {
            preco = `💸 De R$ ${precoCheio.toFixed(2)} por R$ ${precoFinal.toFixed(2)} (${desconto.toFixed(0)}% OFF)`;
            temOferta = true;
        } else {
            preco = `R$ ${precoFinal.toFixed(2)}`;
        }
    } else {
        return null;
    }

    let infoOferta = '';
    if (produto.precos?.tem_oferta && produto.precos?.nome_campanha) {
        infoOferta = ` | 🏷️ ${produto.precos.nome_campanha}`;
    }

    return {
        desc: nomeCompleto,
        price: preco,
        id: codigo,
        faixa: null,
        temOferta: temOferta,
        estoque: estoqueDisponivel,
        precoFinal: precoFinal,
        infoOferta: infoOferta,
        tipoClassificacao: normalizarTipoClassificacao(produto.grupo),
        badge: null
    };
}

// Processa todos os produtos
const todosProcessados = [];
for (let i = 0; i < produtos.length; i++) {
    const item = processarProduto(produtos[i]);
    if (item) {
        todosProcessados.push(item);
    }
}

let productList = [];

// Seleção por faixa de preço
if (modoSelecao === 'faixa_preco' && todosProcessados.length > 0) {
    const ordenados = [...todosProcessados].sort((a, b) => a.precoFinal - b.precoFinal);
    const top3 = ordenados.slice(0, 3);

    if (top3.length >= 3) {
        top3[0].badge = '💰 MAIS EM CONTA';
        top3[1].badge = '⚖️ CUSTO-BENEFÍCIO';
        top3[2].badge = '💎 PREMIUM';
    } else if (top3.length === 2) {
        top3[0].badge = '💰 MAIS EM CONTA';
        top3[1].badge = '💎 PREMIUM';
    } else if (top3.length === 1) {
        top3[0].badge = '💰 MELHOR OPÇÃO';
    }

    top3.forEach(p => p.desc = montarDescricaoLinhaUnica(p));
    productList = top3;

} else {
    productList = [...todosProcessados].slice(0, 5);

    productList.forEach(p => {
        p.desc = montarDescricaoLinhaUnica(p);
    });
}

// Verificar genéricos no top 3
const top3ParaChecagem = productList.slice(0, 3);
const top3TemGenerico = top3ParaChecagem.some(p => p.tipoClassificacao === 'GENERICOS');

let opcoesGenericas = [];

if (!top3TemGenerico) {
    const idsVistos = new Set();

    opcoesGenericas = [...todosProcessados]
        .filter(p => p.tipoClassificacao === 'GENERICOS')
        .filter(p => {
            if (idsVistos.has(p.id)) return false;
            idsVistos.add(p.id);
            return true;
        })
        .sort((a, b) => a.precoFinal - b.precoFinal)
        .slice(0, 3)
        .map(p => {
            const item = { ...p, badge: '💰 GENÉRICO EM DESTAQUE' };
            item.desc = montarDescricaoLinhaUnica(item);
            return item;
        });
}

// Variáveis globais
vars['listaProdutos'] = productList;
vars['listaProdutosQuantidade'] = productList.length;
vars['modoSelecao'] = modoSelecao;
